import java.util.Scanner;

public class SecureBufferOverflowFix {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Fixing the vulnerability by using StringBuilder and ensuring proper bounds checking
        StringBuilder welcomeMessageBuilder = new StringBuilder();
        welcomeMessageBuilder.append("Welcome, ");

        // Performing bounds checking to limit the input size to prevent buffer overflow
        if (name.length() > 50) {
            System.out.println("Input name is too long. Please try again with a shorter name.");
            return;
        }

        welcomeMessageBuilder.append(name).append("!");

        String welcomeMessage = welcomeMessageBuilder.toString();

        System.out.println(welcomeMessage);
    }
}

### Explanation:
취약유형: Buffer Overflow
